import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress, Chip } from '@mui/material';
import response from './response.json';

interface DonationData {
  fundraisingGoal: number;
  totalRaised: number;
  goalProgress: number;
  donorCount: number;
}

export default function Widget() {
  const donationData = response.data as DonationData;
  const { theme, primaryColor } = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: theme === 'light' ? '#FFFFFF' : '#1E293B',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: primaryColor }}>
              Charity Fundraiser
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              ${donationData.totalRaised.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              raised of ${donationData.fundraisingGoal.toLocaleString()} goal
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: primaryColor }}>
                {donationData.goalProgress}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={donationData.goalProgress}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#F3E8FF',
                '& .MuiLinearProgress-bar': {
                  bgcolor: primaryColor,
                  borderRadius: 4,
                }
              }}
            />
          </Box>

          <Stack direction="row" spacing={0.5}>
            <Chip label={`Donors: ${donationData.donorCount}`} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
